    84→function populateMonthOptions() {
    85→    const monthSelect = document.getElementById('monthSelect');
    86→    const currentDate = new Date();
    87→    const currentDay = currentDate.getDate();
    88→    const currentMonth = currentDate.getMonth() + 1; // 0-based to 1-based
    89→    const currentYear = currentDate.getFullYear();
    90→    
    91→    // Clear existing options
    92→    monthSelect.innerHTML = '';
    93→    
    94→    const monthNames = [
    95→        'Enero', 'Febrero', 'Marzo', 'Abril', 'Mayo', 'Junio',
    96→        'Julio', 'Agosto', 'Septiembre', 'Octubre', 'Noviembre', 'Diciembre'
    97→    ];
    98→    
    99→    const options = [];
   100→    
   101→    // Always start from previous month since current month data isn't available until after the 5th
   102→    let startMonth = currentMonth - 1;
   103→    let startYear = currentYear;
   104→    
   105→    if (startMonth < 1) {
   106→        startMonth = 12;
   107→        startYear--;
   108→    }
   109→    
   110→    // Generate 12 months of options going back from start month
   111→    for (let i = 0; i < 12; i++) {
   112→        let month = startMonth - i;
   113→        let year = startYear;
   114→        
   115→        if (month < 1) {
   116→            month += 12;
   117→            year--;
   118→        }
   119→        
   120→        const value = `${year}-${month.toString().padStart(2, '0')}`;
   121→        const label = `${monthNames[month - 1]} ${year}`;
   122→        
   123→        options.push({ value, label, year, month });
   124→    }
   125→    
   126→    // Add options to select (most recent first)
   127→    options.forEach((option, index) => {
   128→        const optionElement = document.createElement('option');
   129→        optionElement.value = option.value;
   130→        optionElement.textContent = option.label;
   131→        if (index === 0) optionElement.selected = true; // Select most recent available
   132→        monthSelect.appendChild(optionElement);
   133→    });
   134→}
