   328→/**
   329→ * Parse EV spread string into individual stats
   330→ */
   331→function parseEVSpread(spreadString) {
   332→    try {
   333→        // Format: "Nature:HP/Atk/Def/SpA/SpD/Spe"
   334→        const parts = spreadString.split(':');
   335→        if (parts.length !== 2) return null;
   336→        
   337→        const nature = parts[0];
   338→        const evParts = parts[1].split('/');
   339→        
   340→        if (evParts.length !== 6) return null;
   341→        
   342→        return {
   343→            nature: nature,
   344→            hp: parseInt(evParts[0]) || 0,
   345→            atk: parseInt(evParts[1]) || 0,
   346→            def: parseInt(evParts[2]) || 0,
   347→            spa: parseInt(evParts[3]) || 0,
   348→            spd: parseInt(evParts[4]) || 0,
   349→            spe: parseInt(evParts[5]) || 0
   350→        };
   351→    } catch (error) {
   352→        console.error('Error parsing EV spread:', spreadString, error);
   353→        return null;
   354→    }
   355→}
