   417→/**
   418→ * Check if a spread matches the EV search criteria
   419→ */
   420→function matchesEVSearch(spread, evSearch) {
   421→    // Support different formats:
   422→    // 1. "252/0/4/0/0/252" - traditional format
   423→    // 2. "HP:252,Atk:252" - stat:value format
   424→    // 3. "Spe>120", "HP<200", "Atk=252" - comparison operators
   425→    // 4. "Spe>120,HP<200" - multiple comparisons
   426→    // 5. "nature:Adamant" - nature filtering
   427→    
   428→    const spreadStr = spread.spread.toLowerCase();
   429→    const evs = spread.evs;
   430→    
   431→    if (!evs) return false;
   432→    
   433→    // Format 5: Nature filtering (nature:Adamant, nature:Jolly, nature!=Adamant)
   434→    if (evSearch.toLowerCase().includes('nature')) {
   435→        return evaluateNatureFilter(evs, evSearch);
   436→    }
   437→    
   438→    // Format 1: Traditional slash-separated format
   439→    if (evSearch.includes('/')) {
   440→        const searchParts = evSearch.split('/').map(part => parseInt(part.trim()) || 0);
   441→        if (searchParts.length === 6) {
   442→            return searchParts[0] === evs.hp &&
   443→                   searchParts[1] === evs.atk &&
   444→                   searchParts[2] === evs.def &&
   445→                   searchParts[3] === evs.spa &&
   446→                   searchParts[4] === evs.spd &&
   447→                   searchParts[5] === evs.spe;
   448→        }
   449→    }
   450→    
   451→    // Format 3: Comparison operators (Spe>120, HP<200, Atk=252)
   452→    if (evSearch.match(/[><!=]/)) {
   453→        return evaluateComparisonFilters(evs, evSearch);
   454→    }
   455→    
   456→    // Format 2: Stat:value format (exact matches)
   457→    if (evSearch.includes(':')) {
   458→        const statMappings = {
   459→            'hp': evs.hp, 'health': evs.hp,
   460→            'atk': evs.atk, 'attack': evs.atk, 'att': evs.atk,
   461→            'def': evs.def, 'defense': evs.def,
   462→            'spa': evs.spa, 'spatk': evs.spa, 'special attack': evs.spa, 'sp.atk': evs.spa,
   463→            'spd': evs.spd, 'spdef': evs.spd, 'special defense': evs.spd, 'sp.def': evs.spd,
   464→            'spe': evs.spe, 'speed': evs.spe
   465→        };
   466→        
   467→        const searchPairs = evSearch.split(',');
   468→        return searchPairs.every(pair => {
   469→            const [stat, value] = pair.split(':').map(s => s.trim());
   470→            const expectedValue = parseInt(value) || 0;
   471→            const actualValue = statMappings[stat.toLowerCase()] || 0;
   472→            return actualValue === expectedValue;
   473→        });
   474→    }
   475→    
   476→    // Fallback: simple string inclusion
   477→    return spreadStr.includes(evSearch);
   478→}
   479→
   480→/**
   481→ * Evaluate nature filters like nature:Adamant, nature:Jolly, nature!=Adamant
   482→ */
   483→function evaluateNatureFilter(evs, searchString) {
   484→    // Split by comma to handle multiple conditions including nature
   485→    const conditions = searchString.split(',').map(s => s.trim());
   486→    
   487→    return conditions.every(condition => {
   488→        if (condition.toLowerCase().includes('nature')) {
   489→            // Handle both nature:Adamant and nature!=Adamant formats
   490→            const match = condition.match(/^nature\s*(!=|=|:)\s*([a-zA-Z]+)$/i);
   491→            if (match) {
   492→                const operator = match[1];
   493→                const targetNature = match[2].trim().toLowerCase();
   494→                const actualNature = evs.nature.toLowerCase();
   495→                
   496→                if (operator === '!=' || operator === '≠') {
   497→                    return actualNature !== targetNature;
   498→                } else {
   499→                    return actualNature === targetNature;
   500→                }
   501→            }
   502→            return false;
   503→        } else {
   504→            // Handle other types of conditions (EV comparisons, etc.)
   505→            if (condition.match(/[><!=]/)) {
   506→                return evaluateComparisonFilters(evs, condition);
   507→            } else if (condition.includes(':')) {
   508→                // Handle stat:value format
   509→                const statMappings = {
   510→                    'hp': evs.hp, 'health': evs.hp,
   511→                    'atk': evs.atk, 'attack': evs.atk, 'att': evs.atk,
   512→                    'def': evs.def, 'defense': evs.def,
   513→                    'spa': evs.spa, 'spatk': evs.spa, 'special attack': evs.spa, 'sp.atk': evs.spa,
   514→                    'spd': evs.spd, 'spdef': evs.spd, 'special defense': evs.spd, 'sp.def': evs.spd,
   515→                    'spe': evs.spe, 'speed': evs.spe
   516→                };
   517→                
   518→                const [stat, value] = condition.split(':').map(s => s.trim());
   519→                const expectedValue = parseInt(value) || 0;
   520→                const actualValue = statMappings[stat.toLowerCase()] || 0;
   521→                return actualValue === expectedValue;
   522→            }
   523→            return true;
   524→        }
   525→    });
   526→}
