   528→/**
   529→ * Evaluate comparison filters like Spe>120, HP<200, Atk=252
   530→ */
   531→function evaluateComparisonFilters(evs, searchString) {
   532→    const statMappings = {
   533→        'hp': evs.hp, 'health': evs.hp,
   534→        'atk': evs.atk, 'attack': evs.atk, 'att': evs.atk,
   535→        'def': evs.def, 'defense': evs.def,
   536→        'spa': evs.spa, 'spatk': evs.spa, 'special attack': evs.spa, 'sp.atk': evs.spa, 'spatk': evs.spa,
   537→        'spd': evs.spd, 'spdef': evs.spd, 'special defense': evs.spd, 'sp.def': evs.spd, 'spdef': evs.spd,
   538→        'spe': evs.spe, 'speed': evs.spe
   539→    };
   540→    
   541→    // Split by comma to handle multiple conditions
   542→    const conditions = searchString.split(',').map(s => s.trim());
   543→    
   544→    return conditions.every(condition => {
   545→        // Match patterns like "Spe>120", "HP<=200", "Atk=252", "Def!=0"
   546→        const match = condition.match(/^([a-zA-Z]+)\s*(>=|<=|>|<|!=|=)\s*(\d+)$/);
   547→        
   548→        if (!match) {
   549→            console.warn(`Invalid comparison format: ${condition}`);
   550→            return false;
   551→        }
   552→        
   553→        const [, statName, operator, valueStr] = match;
   554→        const targetValue = parseInt(valueStr);
   555→        const actualValue = statMappings[statName.toLowerCase()];
   556→        
   557→        if (actualValue === undefined) {
   558→            console.warn(`Unknown stat: ${statName}`);
   559→            return false;
   560→        }
   561→        
   562→        switch (operator) {
   563→            case '>':
   564→                return actualValue > targetValue;
   565→            case '>=':
   566→                return actualValue >= targetValue;
