   427→ * Check if a spread matches the EV search criteria
   428→ */
   429→function matchesEVSearch(spread, evSearch) {
   430→    // Support different formats:
   431→    // 1. "252/0/4/0/0/252" - traditional format
   432→    // 2. "HP:252,Atk:252" - stat:value format
   433→    // 3. "Spe>120", "HP<200", "Atk=252" - comparison operators
   434→    // 4. "Spe>120,HP<200" - multiple comparisons
   435→    // 5. "nature:Adamant" - nature filtering
   436→    
   437→    const spreadStr = spread.spread.toLowerCase();
   438→    const evs = spread.evs;
   439→    
   440→    if (!evs) return false;
   441→    
   442→    // Format 5: Nature filtering (nature:Adamant, nature:Jolly, nature!=Adamant)
   443→    if (evSearch.toLowerCase().includes('nature')) {
   444→        return evaluateNatureFilter(evs, evSearch);
   445→    }
   446→    
   447→    // Format 1: Traditional slash-separated format
   448→    if (evSearch.includes('/')) {
   449→        const searchParts = evSearch.split('/').map(part => parseInt(part.trim()) || 0);
   450→        if (searchParts.length === 6) {
   451→            return searchParts[0] === evs.hp &&
   452→                   searchParts[1] === evs.atk &&
   453→                   searchParts[2] === evs.def &&
   454→                   searchParts[3] === evs.spa &&
   455→                   searchParts[4] === evs.spd &&
   456→                   searchParts[5] === evs.spe;
   457→        }
   458→    }
   459→    
   460→    // Format 3: Comparison operators (Spe>120, HP<200, Atk=252)
   461→    if (evSearch.match(/[><!=]/)) {
   462→        return evaluateComparisonFilters(evs, evSearch);
   463→    }
   464→    
   465→    // Format 2: Stat:value format (exact matches)
   466→    if (evSearch.includes(':')) {
   467→        const statMappings = {
   468→            'hp': evs.hp, 'health': evs.hp,
   469→            'atk': evs.atk, 'attack': evs.atk, 'att': evs.atk,
   470→            'def': evs.def, 'defense': evs.def,
   471→            'spa': evs.spa, 'spatk': evs.spa, 'special attack': evs.spa, 'sp.atk': evs.spa,
   472→            'spd': evs.spd, 'spdef': evs.spd, 'special defense': evs.spd, 'sp.def': evs.spd,
   473→            'spe': evs.spe, 'speed': evs.spe
   474→        };
   475→        
   476→        const searchPairs = evSearch.split(',');
   477→        return searchPairs.every(pair => {
   478→            const [stat, value] = pair.split(':').map(s => s.trim());
   479→            const expectedValue = parseInt(value) || 0;
   480→            const actualValue = statMappings[stat.toLowerCase()] || 0;
   481→            return actualValue === expectedValue;
   482→        });
   483→    }
   484→    
   485→    // Fallback: simple string inclusion
   486→    return spreadStr.includes(evSearch);
   487→}
